mapper.select:
SELECT

FROM biz_public_archive_application


		AND applicant_type = #{vo.applicantType}


		AND natural_person_name LIKE CONCAT('%', #{vo.naturalPersonName}, '%')


		AND natural_person_id_card = #{vo.naturalPersonIdCard}


		AND legal_person_name LIKE CONCAT('%', #{vo.legalPersonName}, '%')


		AND legal_person_unified_code = #{vo.legalPersonUnifiedCode}


		AND application_no LIKE CONCAT('%', #{vo.applicationNo}, '%')


		AND document_no LIKE CONCAT('%', #{vo.documentNo}, '%')


		AND file_name LIKE CONCAT('%', #{vo.fileName}, '%')


		AND provide_method = #{vo.provideMethod}


		AND obtain_method = #{vo.obtainMethod}


		AND application_status = #{vo.applicationStatus}


		AND application_time >= #{vo.applicationTime}

	AND is_deleted = 0

ORDER BY create_time DESC
